 */
let PfLinkComponent = class PfLinkComponent {
    constructor() {
        this.href = '';
        this.variant = 'default';
        this.target = '';
        this.rel = '';
        this.external = null;
        this.ExternalIcon = ExternalLink;
    }
    get isExternal() {
        return this.external ?? isExternalUrl(this.href);
    }
    get finalTarget() {
        if (this.target)
            return this.target;
        return this.isExternal ? '_blank' : null;
    }
    get finalRel() {
        if (this.rel)
            return this.rel;
        return this.isExternal ? 'noreferrer noopener' : null;
    }
